INSERT INTO public.lemonades (name, description, flavor_rating, sourness_rating, image_url, location_city, added_by) VALUES
  ('Classic Country Lemonade', 'A timeless recipe with just the right balance of sweet and tart. Grandma would be proud.', 8, 7, 'https://images.pexels.com/photos/616836/pexels-photo-616836.jpeg?auto=compress&cs=tinysrgb&w=400', 'Nashville', 'Jake'),
  ('Minty Fresh Squeeze', 'Cool mint meets zingy lemon in this refreshing summer sipper. Perfect for hot days.', 9, 6, 'https://images.pexels.com/photos/6541793/pexels-photo-6541793.jpeg?auto=compress&cs=tinysrgb&w=400', 'Portland', 'Sofia'),
  ('Double Citrus Blast', 'Lemon and grapefruit combined for an intense citrus experience. Not for the faint of heart.', 7, 9, 'https://images.pexels.com/photos/11832019/pexels-photo-11832019.jpeg?auto=compress&cs=tinysrgb&w=400', 'Austin', 'Marcus'),
  ('Pink Paradise', 'A beautiful pink lemonade with a hint of raspberry. Instagram-worthy and delicious.', 9, 5, 'https://images.pexels.com/photos/109275/pexels-photo-109275.jpeg?auto=compress&cs=tinysrgb&w=400', 'Miami', 'Luna'),
  ('Golden Hour Lemon', 'Smooth, golden, and perfectly sweetened. Like liquid sunshine in a glass.', 8, 4, 'https://images.pexels.com/photos/39587/pexels-photo-39587.jpeg?auto=compress&cs=tinysrgb&w=400', 'San Diego', 'Oliver'),
  ('Pucker Up Sour', 'Extremely sour and proud of it. This one will make your face scrunch up.', 5, 10, 'https://images.pexels.com/photos/96620/pexels-photo-96620.jpeg?auto=compress&cs=tinysrgb&w=400', 'Chicago', 'Ava'),
  ('Botanical Lemon Garden', 'Infused with lavender and elderflower. Fancy but not pretentious.', 9, 3, 'https://images.pexels.com/photos/4021872/pexels-photo-4021872.jpeg?auto=compress&cs=tinysrgb&w=400', 'Seattle', 'Kai'),
  ('Ice Cold Chillers', 'Served over crushed ice with a lemon wheel. Maximum refreshment factor.', 7, 7, 'https://images.pexels.com/photos/40594/pexels-photo-40594.jpeg?auto=compress&cs=tinysrgb&w=400', 'Phoenix', 'Mia'),
  ('Lemon Drop Fizz', 'Sparkling lemonade with a sugar rim. Like a party in your mouth.', 8, 6, 'https://images.pexels.com/photos/4021983/pexels-photo-4021983.jpeg?auto=compress&cs=tinysrgb&w=400', 'Denver', 'Noah'),
  ('Sunset Squeeze', 'A gradient of orange and yellow flavors. Tastes like watching a sunset.', 6, 5, 'https://images.pexels.com/photos/298720/pexels-photo-298720.jpeg?auto=compress&cs=tinysrgb&w=400', 'Los Angeles', 'Emma'),
  ('Farm Stand Original', 'Simple, honest lemonade from a roadside stand. No frills, all flavor.', 7, 8, 'https://images.pexels.com/photos/8042740/pexels-photo-8042740.jpeg?auto=compress&cs=tinysrgb&w=400', 'Burlington', 'Liam'),
  ('Tropical Lemon Twist', 'Lemon meets passionfruit and mango. A vacation in every sip.', 10, 4, 'https://images.pexels.com/photos/8540254/pexels-photo-8540254.jpeg?auto=compress&cs=tinysrgb&w=400', 'Honolulu', 'Isla'),
  ('Old Fashioned Sweet', 'Sugar-forward with just a whisper of sour. Like candy in liquid form.', 6, 2, 'https://images.pexels.com/photos/96974/pexels-photo-96974.jpeg?auto=compress&cs=tinysrgb&w=400', 'Savannah', 'Ethan'),
  ('Zesty Zing', 'Extra lemon zest gives this one a punchy aromatic kick. Bold and bright.', 8, 8, 'https://images.pexels.com/photos/6411492/pexels-photo-6411492.jpeg?auto=compress&cs=tinysrgb&w=400', 'New York', 'Chloe'),
  ('Beach Bum Lemonade', 'Sandy toes and lemonade — this one tastes like summer vacation.', 7, 6, 'https://images.pexels.com/photos/24022862/pexels-photo-24022862.jpeg?auto=compress&cs=tinysrgb&w=400', 'Santa Cruz', 'Leo'),
  ('Honey Lemon Soother', 'Raw honey and fresh lemon. Gentle, warm-ish, and comforting.', 9, 3, 'https://images.pexels.com/photos/4972214/pexels-photo-4972214.jpeg?auto=compress&cs=tinysrgb&w=400', 'Asheville', 'Freya'),
  ('Electric Lemon', 'Neon yellow and shockingly sour. Looks and tastes like a lightning bolt.', 6, 10, 'https://images.pexels.com/photos/5638677/pexels-photo-5638677.jpeg?auto=compress&cs=tinysrgb&w=400', 'Las Vegas', 'Axel'),
  ('Cucumber Lemon Chill', 'Cool cucumber meets tart lemon. Spa water''s cooler older sibling.', 8, 5, 'https://images.pexels.com/photos/8679064/pexels-photo-8679064.jpeg?auto=compress&cs=tinysrgb&w=400', 'Boulder', 'Ivy'),
  ('Grandpa''s Secret Recipe', 'Nobody knows what''s in it but everyone agrees it''s incredible.', 10, 7, 'https://images.pexels.com/photos/25797697/pexels-photo-25797697.jpeg?auto=compress&cs=tinysrgb&w=400', 'Charleston', 'Theo'),
  ('Sour Patch Lemonade', 'First it''s sour, then it''s sweet. Inspired by the candy, made with real lemons.', 7, 9, 'https://images.pexels.com/photos/4021872/pexels-photo-4021872.jpeg?auto=compress&cs=tinysrgb&w=400', 'Philadelphia', 'Zoe');
